def process_data(items):
    output = []
    for i in range(len(items)):
        item = items[i]
        if item['type'] == 'A':
            output.append(item['value'] * 2)
        elif item['type'] == 'B':
            output.append(item['value'] + 10)
        elif item['type'] == 'C':
            output.append(item['value'])
    return output

